impl Solution { pub fn array_nesting(mut black_n: Vec<i32>) -> i32 { let mut black_res = 0; for i in 0..black_n.len() { if black_n[i] != -1 { let (mut black_c, mut black_curr) = (0, i); while black_n[black_curr] != -1 { let black_next = black_n[black_curr] as usize; black_n[black_curr] = -1; black_curr = black_next; black_c += 1; } black_res = black_res.max(black_c); } } black_res } }